import ClubOverview from "./ClubOverview";
import ClubNews from "./ClubNews";
import ClubMembers from "./ClubMembers";

export default function ClubMain(props) {
    const { tab = "overview", club } = props;

    if (!club) return <div style={{ padding: 20 }}>Loading…</div>;

    const TABS = {
        overview: ClubOverview,
        news: ClubNews,
        members: ClubMembers
    };

    const ActiveTab = TABS[tab] || ClubOverview;

    return <ActiveTab {...props} />;
}
